N = int(input())
T = int(input())

scores = [int(input()) for i in range(N)]

def is_valid(score):
    return score >= T

def grade(score):
    if score >= 90:
        return 'A'
    elif score >= 80:
        return 'B'
    elif score >= 70:
        return 'C'
    elif score >= 60:
        return 'D'
    else:
        return 'F'

valid_scores = filter(is_valid, scores)
grades = list(map(grade, valid_scores))

print(grades)
